const e=JSON.parse('{"key":"v-4f261ca3","path":"/study/CSS/%E6%B8%85%E9%99%A4%E6%B5%AE%E5%8A%A8.html","title":"清除浮动","lang":"zh-CN","frontmatter":{"title":"清除浮动","icon":"markdown","order":4,"date":"2023-03-02T00:00:00.000Z","category":["CSS"],"tag":["清除浮动"],"description":"特点 浮动的特点，可以用八个字总结：脱标、贴边、字围和收缩。 为了更好说明，请看下图： 当框 1 向左浮动时，它脱离文档流（脱标）并且向左移动（贴边），直到它的左边缘碰到包含框的左边缘。因为它不再处于文档流中，所以它不占据空间，实际上覆盖住了框 2，使框 2 从视图中消失。如果框 2 中有文字，就会围着框 1 排开（字围）。 如果把所有三个框都向左浮动，那么框 1 向左浮动直到碰到包含框，另外两个框向左浮动直到碰到前一个浮动框。","head":[["meta",{"property":"og:url","content":"https://luotianxu1.github.io/study/CSS/%E6%B8%85%E9%99%A4%E6%B5%AE%E5%8A%A8.html"}],["meta",{"property":"og:title","content":"清除浮动"}],["meta",{"property":"og:description","content":"特点 浮动的特点，可以用八个字总结：脱标、贴边、字围和收缩。 为了更好说明，请看下图： 当框 1 向左浮动时，它脱离文档流（脱标）并且向左移动（贴边），直到它的左边缘碰到包含框的左边缘。因为它不再处于文档流中，所以它不占据空间，实际上覆盖住了框 2，使框 2 从视图中消失。如果框 2 中有文字，就会围着框 1 排开（字围）。 如果把所有三个框都向左浮动，那么框 1 向左浮动直到碰到包含框，另外两个框向左浮动直到碰到前一个浮动框。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-02T11:25:25.000Z"}],["meta",{"property":"article:tag","content":"清除浮动"}],["meta",{"property":"article:published_time","content":"2023-03-02T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-02T11:25:25.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"清除浮动\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-03-02T00:00:00.000Z\\",\\"dateModified\\":\\"2023-03-02T11:25:25.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"特点","slug":"特点","link":"#特点","children":[]},{"level":2,"title":"缺点","slug":"缺点","link":"#缺点","children":[]},{"level":2,"title":"清理浮动","slug":"清理浮动","link":"#清理浮动","children":[{"level":3,"title":"给浮动元素的父元素添加高度（扩展性不好）","slug":"给浮动元素的父元素添加高度-扩展性不好","link":"#给浮动元素的父元素添加高度-扩展性不好","children":[]},{"level":3,"title":"clear:both","slug":"clear-both","link":"#clear-both","children":[]},{"level":3,"title":"伪元素清除浮动","slug":"伪元素清除浮动","link":"#伪元素清除浮动","children":[]},{"level":3,"title":"给父元素使用 overflow:hidden","slug":"给父元素使用-overflow-hidden","link":"#给父元素使用-overflow-hidden","children":[]},{"level":3,"title":"br 标签清浮动","slug":"br-标签清浮动","link":"#br-标签清浮动","children":[]}]}],"git":{"createdTime":1677756325000,"updatedTime":1677756325000,"contributors":[{"name":"Luotianxu","email":"1265062404@qq.com","commits":1}]},"readingTime":{"minutes":3.83,"words":1149},"filePathRelative":"study/CSS/清除浮动.md","localizedDate":"2023年3月2日","excerpt":"<h2> 特点</h2>\\n<p>浮动的特点，可以用八个字总结：脱标、贴边、字围和收缩。</p>\\n<p>为了更好说明，请看下图：\\n当框 1 向左浮动时，它脱离文档流（脱标）并且向左移动（贴边），直到它的左边缘碰到包含框的左边缘。因为它不再处于文档流中，所以它不占据空间，实际上覆盖住了框 2，使框 2 从视图中消失。如果框 2 中有文字，就会围着框 1 排开（字围）。</p>\\n<p>如果把所有三个框都向左浮动，那么框 1 向左浮动直到碰到包含框，另外两个框向左浮动直到碰到前一个浮动框。</p>\\n<figure><img src=\\"/img/study/css/float.jpg\\" alt=\\" \\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption> </figcaption></figure>","autoDesc":true}');export{e as data};
